namespace BlazorApp.Services;

public class Notification
{
    public int Id { get; set; }
    public string Message { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
}

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    public Task<List<Notification>> GetInitialNotificationsAsync()
    {
        var notifications = new List<Notification>
        {
            new() { Id = _nextId++, Message = "Welcome to the app!", Timestamp = DateTime.UtcNow.AddMinutes(-10) },
            new() { Id = _nextId++, Message = "Your profile was updated.", Timestamp = DateTime.UtcNow.AddMinutes(-5) },
            new() { Id = _nextId++, Message = "New feature available: Dark Mode.", Timestamp = DateTime.UtcNow.AddMinutes(-1) },
        };
        return Task.FromResult(notifications);
    }

    public Task<List<Notification>> CheckForNewNotificationsAsync(int afterId)
    {
        var newNotifications = new List<Notification>();

        // Simulate ~30% chance of a new notification each poll
        if (Random.Shared.Next(0, 10) < 3)
        {
            lock (_lock)
            {
                newNotifications.Add(new Notification
                {
                    Id = _nextId++,
                    Message = $"New event at {DateTime.UtcNow:HH:mm:ss}",
                    Timestamp = DateTime.UtcNow,
                });
            }
        }

        return Task.FromResult(newNotifications);
    }
}

@page "/notifications"
@rendermode InteractiveServer
@inject BlazorApp.Services.NotificationService NotificationService
@implements IAsyncDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@notifications.Count</span></h1>

@if (notifications.Count == 0)
{
    <p>No notifications yet.</p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item">
                <strong>@n.Message</strong>
                <small class="text-muted ms-2">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    [PersistentState]
    public List<BlazorApp.Services.Notification>? Notifications { get; set; }

    private List<BlazorApp.Services.Notification> notifications = new();
    private CancellationTokenSource? _cts;

    protected override async Task OnInitializedAsync()
    {
        if (Notifications is not null)
        {
            notifications = Notifications;
        }
        else
        {
            notifications = await NotificationService.GetInitialNotificationsAsync();
            Notifications = notifications;
        }
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(5000, cancellationToken);

            var lastId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
            var newItems = await NotificationService.CheckForNewNotificationsAsync(lastId);

            if (newItems.Count > 0)
            {
                notifications.AddRange(newItems);
                Notifications = notifications;
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public async ValueTask DisposeAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }
    }
}

